body:
The following output is incorrect. The memory is only used by the design, but it is placed in the testbench directory:

```
FIRRTL version 4.0.0
circuit Testbench: %[[
  {
    "class": "sifive.enterprise.firrtl.MarkDUTAnnotation",
    "target": "~Testbench|DUT"
  },
  {
    "class": "sifive.enterprise.firrtl.TestBenchDirAnnotation",
    "dirname": "testbench"
  }
]]
  module DUT:
    input clock: Clock
    input r: {addr: UInt<3>, en: UInt<1> flip data: UInt<32>}
    input w: {addr: UInt<3>, en: UInt<1> data: UInt<32>, mask: UInt<1>}

    mem memory:
      data-type => UInt<32>
      depth => 16
      reader => r
      writer => w
      read-latency => 1
      write-latency => 1
      read-under-write => undefined

    memory.r.addr <= r.addr
    memory.r.en <= r.en
    memory.r.clk <= clock
    r.data <= memory.r.data

    memory.w.addr <= w.addr
    memory.w.en <= w.en
    memory.w.clk <= clock
    memory.w.data <= w.data
    memory.w.mask <= w.mask

  public module Testbench:
    input clock: Clock
    input r: {addr: UInt<3>, en: UInt<1> flip data: UInt<32>}
    input w: {addr: UInt<3>, en: UInt<1> data: UInt<32>, mask: UInt<1>}

    inst dut of DUT
    connect dut.clock, clock
    connect dut.r, r
    connect dut.w, w
```

This is incorrectly compiling to:

``` verilog
// Generated by CIRCT firtool-1.66.0-92-g077826e06
module DUT(
  input         clock,
  input  [2:0]  r_addr,
  input         r_en,
  output [31:0] r_data,
  input  [2:0]  w_addr,
  input         w_en,
  input  [31:0] w_data,
  input         w_mask
);

  memory_16x32 memory_ext (
    .R0_addr ({1'h0, r_addr}),
    .R0_en   (r_en),
    .R0_clk  (clock),
    .R0_data (r_data),
    .W0_addr ({1'h0, w_addr}),
    .W0_en   (w_en & w_mask),
    .W0_clk  (clock),
    .W0_data (w_data)
  );
endmodule


// ----- 8< ----- FILE "testbench/memory_16x32.sv" ----- 8< -----

// Generated by CIRCT firtool-1.66.0-92-g077826e06
// VCS coverage exclude_file
module memory_16x32(
  input  [3:0]  R0_addr,
  input         R0_en,
                R0_clk,
  output [31:0] R0_data,
  input  [3:0]  W0_addr,
  input         W0_en,
                W0_clk,
  input  [31:0] W0_data
);

  reg [31:0] Memory[0:15];
  reg        _R0_en_d0;
  reg [3:0]  _R0_addr_d0;
  always @(posedge R0_clk) begin
    _R0_en_d0 <= R0_en;
    _R0_addr_d0 <= R0_addr;
  end // always @(posedge)
  always @(posedge W0_clk) begin
    if (W0_en & 1'h1)
      Memory[W0_addr] <= W0_data;
  end // always @(posedge)
  assign R0_data = _R0_en_d0 ? Memory[_R0_addr_d0] : 32'bx;
endmodule


// ----- 8< ----- FILE "testbench/Testbench.sv" ----- 8< -----

// Generated by CIRCT firtool-1.66.0-92-g077826e06
// VCS coverage exclude_file
module Testbench(
  input         clock,
  input  [2:0]  r_addr,
  input         r_en,
  output [31:0] r_data,
  input  [2:0]  w_addr,
  input         w_en,
  input  [31:0] w_data,
  input         w_mask
);

  DUT dut (
    .clock  (clock),
    .r_addr (r_addr),
    .r_en   (r_en),
    .r_data (r_data),
    .w_addr (w_addr),
    .w_en   (w_en),
    .w_data (w_data),
    .w_mask (w_mask)
  );
endmodule
```

I expect that this is a regression I introduced in: https://github.com/llvm/circt/pull/6741
